css:
/* 8-bit text forcing & Anti-aliasing removal */
* { text-transform: uppercase !important; -webkit-font-smoothing: none !important; font-smooth: never !important; }

/* The iconic maze double-border on cards and panels */
.bg-theme-surface, .card, .modal-content {
  border: 4px double #1919a6 !important;
  box-shadow: inset 0 0 0 2px #000, 0 0 0 2px #000, 0 0 0 4px #1919a6 !important;
  margin-bottom: 8px;
  background-color: #000 !important;
}

/* Header and Topbar double border */
header, .border-b {
  border-bottom: 4px double #1919a6 !important;
}

/* Forms and Inputs */
input, select, textarea {
  font-family: "Press Start 2P", "DotGothic16", cursive !important;
  border: 2px solid #1919a6 !important;
  background-color: #000 !important;
  color: #ffff00 !important;
}
input:focus, textarea:focus, select:focus {
  border-color: #ffb8ff !important;
  box-shadow: none !important;
}

/* Arcade Button Hover & Click logic */
.btn-primary {
  background: #ffff00 !important;
  color: #000 !important;
  border: 2px solid #000 !important;
  box-shadow: 4px 4px 0px #ffb8ff !important;
  transition: transform 0.1s, box-shadow 0.1s;
}
.btn-primary:hover {
  transform: translate(-2px, -2px);
  box-shadow: 6px 6px 0px #ffb8ff !important;
  background: #fff !important;
}
.btn-primary:active {
  transform: translate(2px, 2px);
  box-shadow: 2px 2px 0px #ffb8ff !important;
}

/* Secondary buttons */
.btn-secondary {
  background: #000 !important;
  border: 2px solid #ffb8ff !important;
  color: #ffb8ff !important;
}
.btn-secondary:hover {
  background: #ffb8ff !important;
  color: #000 !important;
}

/* Waka Waka Selection */
::selection { background: #ffff00 !important; color: #000 !important; }
::-moz-selection { background: #ffff00 !important; color: #000 !important; }

/* Table row ghost hover */
tr:hover td {
  background: #1919a6 !important;
  color: #fff !important;
}
tr:hover td a, tr:hover td span, tr:hover td svg { color: #fff !important; }
